@Configuration
@EnableAuthorizationServer
class AuthorizationServerConfig extends AuthorizationServerConfigurerAdapter {

    private final UserDetailsService userDetailsService;
    private final ClientDetailsService clientDetailsService;
    private final AuthenticationManager authenticationManager;

    private Map<String, String> authorizationCodes = new HashMap<>();
    private long expirationTime = 10 * 60 * 1000; // 10 minutes

    public AuthorizationServerConfig(UserDetailsService userDetailsService, ClientDetailsService clientDetailsService, AuthenticationManager authenticationManager) {
        this.userDetailsService = userDetailsService;
        this.clientDetailsService = clientDetailsService;
        this.authenticationManager = authenticationManager;
    }

    @Override
    public void configure(ClientDetailsServiceConfigurer clients) throws Exception {
        clients.inMemory()
            .withClient("client")
            .secret("{noop}secret")
            .authorizedGrantTypes("authorization_code", "refresh_token")
            .scopes("read", "write")
            .redirectUris("http://localhost:8080/callback"); // Example redirect URI
    }

    @Override
    public void configure(AuthorizationEndpointConfigurer endpoints) throws Exception {
        endpoints.authenticationManager(authenticationManager)
                .userDetailsService(userDetailsService);
    }

    // Custom Authorization Endpoint to validate redirect_uri
    @Bean
    public AuthorizationEndpoint authorizationEndpoint() {
        return new AuthorizationEndpoint() {
            @Override
            protected boolean isApproved(Map<String, String> requestParameters, ClientDetails client) {
                String redirectUri = requestParameters.get("redirect_uri");
                if (redirectUri == null || !isValidRedirectUri(redirectUri, client)) {
                    throw new IllegalArgumentException("Invalid redirect URI");
                }
                return super.isApproved(requestParameters, client);
            }

            private boolean isValidRedirectUri(String redirectUri, ClientDetails client) {
                String registeredRedirectUri = client.getRegisteredRedirectUri().iterator().next();
                return redirectUri.startsWith(registeredRedirectUri.substring(0, registeredRedirectUri.indexOf("://") + 3));
            }
        };
    }

    @Bean
    public TokenStore tokenStore() {
        return new InMemoryTokenStore();
    }
}

